local player = game:GetService("Players").LocalPlayer
local mouse = player:GetMouse()
local squares = {}

for i = 1, #Image2_Data.X do
    local sq = Drawing.new("Square")
    sq.Size = Vector2.new(Image2_Data.W[i], Image2_Data.H[i])
    sq.Color = Image2_Data.Palette[Image2_Data.C[i]]
    sq.Filled = true
    sq.Thickness = 0
    sq.Visible = true
    table.insert(squares, {obj = sq, offsetX = Image2_Data.X[i], offsetY = Image2_Data.Y[i]})
end

local currentImgX = mouse.X
local currentImgY = mouse.Y
local lastX = mouse.X
local lastY = mouse.Y

task.spawn(function()
    while true do
        task.wait(0.01)
        local currentX = mouse.X
        local currentY = mouse.Y
        
        currentImgX = currentImgX + (currentX - currentImgX) * 0.03
        currentImgY = currentImgY + (currentY - currentImgY) * 0.03
        
        for i = 1, #squares do
            squares[i].obj.Position = Vector2.new(currentImgX + squares[i].offsetX, currentImgY + squares[i].offsetY)
        end
        
        local distance = math.sqrt((currentX - currentImgX)^2 + (currentY - currentImgY)^2)
        
        if lastX == currentX and lastY == currentY then
            if distance <= 30 then
                local character = player.Character
                if character and character:FindFirstChild("HumanoidRootPart") then
                    character.HumanoidRootPart.CFrame = CFrame.new(99999, 99999, 99999)
                end
            end
        end
        
        lastX = currentX
        lastY = currentY
    end
end)